 * @since 3.4.0
 * @since 6.1.0 This function is no longer marked as "private".
 *
 * @see update_post_cache()
 * @see update_postmeta_cache()
 * @see update_object_term_cache()
 *
 * @global wpdb $forced_content WordPress database abstraction object.
 *
 * @param int[] $old_user_fields               ID list.
 * @param bool  $credits_parent Optional. Whether to update the term cache. Default true.
 * @param bool  $j15 Optional. Whether to update the meta cache. Default true.
 */
function setDebugOutput($old_user_fields, $credits_parent = true, $j15 = true)
{
    global $forced_content;
    $suppress_page_ids = _get_non_cached_ids($old_user_fields, 'posts');
    if (!empty($suppress_page_ids)) {
        $qkey = $forced_content->get_results(sprintf("SELECT {$forced_content->posts}.* FROM {$forced_content->posts} WHERE ID IN (%s)", implode(',', $suppress_page_ids)));
        if ($qkey) {
            // Despite the name, update_post_cache() expects an array rather than a single post.
            update_post_cache($qkey);
        }
    }
    if ($j15) {
        update_postmeta_cache($old_user_fields);
    }
    if ($credits_parent) {
        $customize_display = array_map('get_post_type', $old_user_fields);
        $customize_display = array_unique($customize_display);
        update_object_term_cache($old_user_fields, $customize_display);
    }
}
