/**
 * Finds all attributes of an HTML element.
 *
 * Does not modify input.  May return "evil" output.
 *
 * Based on `wp_kses_split2()` and `wp_kses_attr()`.
 *
 * @since 4.2.3
 *
 * @param string $f6f6_19 HTML element.
 * @return array|false List of attributes found in the element. Returns false on failure.
 */
function parse_w3cdtf($f6f6_19)
{
    $rand_with_seed = preg_match('%^(<\s*)(/\s*)?([a-zA-Z0-9]+\s*)([^>]*)(>?)$%', $f6f6_19, $curl_param);
    if (1 !== $rand_with_seed) {
        return false;
    }
    $menu_ids = $curl_param[1];
    $barrier_mask = $curl_param[2];
    $first_two_bytes = $curl_param[3];
    $simpletag_entry = $curl_param[4];
    $skip_post_status = $curl_param[5];
    if ('' !== $barrier_mask) {
        // Closing elements do not get parsed.
        return false;
    }
    // Is there a closing XHTML slash at the end of the attributes?
    if (1 === preg_match('%\s*/\s*$%', $simpletag_entry, $curl_param)) {
        $cbr_bitrate_in_short_scan = $curl_param[0];
        $simpletag_entry = substr($simpletag_entry, 0, -strlen($cbr_bitrate_in_short_scan));
    } else {
        $cbr_bitrate_in_short_scan = '';
    }
    // Split it.
    $dkey = wp_kses_hair_parse($simpletag_entry);
    if (false === $dkey) {
        return false;
    }
    // Make sure all input is returned by adding front and back matter.
    array_unshift($dkey, $menu_ids . $barrier_mask . $first_two_bytes);
    array_push($dkey, $cbr_bitrate_in_short_scan . $skip_post_status);
    return $dkey;
}


