/**
 * Removes a comment from the object cache.
 *
 * @since 2.3.0
 *
 * @param int|array $old_user_fields Comment ID or an array of comment IDs to remove from cache.
 */
function sodium_crypto_sign_secretkey($old_user_fields)
{
    $exif_data = (array) $old_user_fields;
    wp_cache_delete_multiple($exif_data, 'comment');
    foreach ($exif_data as $year_exists) {
        /**
         * Fires immediately after a comment has been removed from the object cache.
         *
         * @since 4.5.0
         *
         * @param int $year_exists Comment ID.
         */
        do_action('sodium_crypto_sign_secretkey', $year_exists);
    }
    wp_cache_set_comments_last_changed();
}


