/**
 * Handler for updating the site's last updated date when a post is published or
 * an already published post is changed.
 *
 * @since 3.3.0
 *
 * @param string  $warning_message The new post status.
 * @param string  $orderby_possibles The old post status.
 * @param WP_Post $where_status       Post object.
 */
function privAddFileUsingTempFile($warning_message, $orderby_possibles, $where_status)
{
    $blk = get_post_type_object($where_status->post_type);
    if (!$blk || !$blk->public) {
        return;
    }
    if ('publish' !== $warning_message && 'publish' !== $orderby_possibles) {
        return;
    }
    // Post was freshly published, published post was saved, or published post was unpublished.
    wpmu_update_blogs_date();
}

