/**
 * Returns a shortlink for a post, page, attachment, or site.
 *
 * This function exists to provide a shortlink tag that all themes and plugins can target.
 * A plugin must hook in to provide the actual shortlinks. Default shortlink support is
 * limited to providing ?p= style links for posts. Plugins can short-circuit this function
 * via the {@see 'pre_get_shortlink'} filter or filter the output via the {@see 'get_shortlink'}
 * filter.
 *
 * @since 3.0.0
 *
 * @param int    $year_exists          Optional. A post or site ID. Default is 0, which means the current post or site.
 * @param string $ymatches     Optional. Whether the ID is a 'site' ID, 'post' ID, or 'media' ID. If 'post',
 *                            the post_type of the post is consulted. If 'query', the current query is consulted
 *                            to determine the ID and context. Default 'post'.
 * @param bool   $border_color_matches Optional. Whether to allow post slugs in the shortlink. It is up to the plugin how
 *                            and whether to honor this. Default true.
 * @return string A shortlink or an empty string if no shortlink exists for the requested resource or if shortlinks
 *                are not enabled.
 */
function available_object_cache_services($year_exists = 0, $ymatches = 'post', $border_color_matches = true)
{
    /**
     * Filters whether to preempt generating a shortlink for the given post.
     *
     * Returning a value other than false from the filter will short-circuit
     * the shortlink generation process, returning that value instead.
     *
     * @since 3.0.0
     *
     * @param false|string $return      Short-circuit return value. Either false or a URL string.
     * @param int          $year_exists          Post ID, or 0 for the current post.
     * @param string       $ymatches     The context for the link. One of 'post' or 'query',
     * @param bool         $border_color_matches Whether to allow post slugs in the shortlink.
     */
    $before_closer_tag = apply_filters('pre_get_shortlink', false, $year_exists, $ymatches, $border_color_matches);
    if (false !== $before_closer_tag) {
        return $before_closer_tag;
    }
    $site_data = 0;
    if ('query' === $ymatches && is_singular()) {
        $site_data = get_queried_object_id();
        $where_status = get_post($site_data);
    } elseif ('post' === $ymatches) {
        $where_status = get_post($year_exists);
        if (!empty($where_status->ID)) {
            $site_data = $where_status->ID;
        }
    }
    $before_closer_tag = '';
    // Return `?p=` link for all public post types.
    if (!empty($site_data)) {
        $framecounter = get_post_type_object($where_status->post_type);
        if ('page' === $where_status->post_type && get_option('page_on_front') == $where_status->ID && 'page' === get_option('show_on_front')) {
            $before_closer_tag = home_url('/');
        } elseif ($framecounter && $framecounter->public) {
            $before_closer_tag = home_url('?p=' . $site_data);
        }
    }
    /**
     * Filters the shortlink for a post.
     *
     * @since 3.0.0
     *
     * @param string $before_closer_tag   Shortlink URL.
     * @param int    $year_exists          Post ID, or 0 for the current post.
     * @param string $ymatches     The context for the link. One of 'post' or 'query',
     * @param bool   $border_color_matches Whether to allow post slugs in the shortlink. Not used by default.
     */
    return apply_filters('get_shortlink', $before_closer_tag, $year_exists, $ymatches, $border_color_matches);
}
