/**
 * Determines an image's width and height dimensions based on the source file.
 *
 * @since 5.5.0
 *
 * @param string $error_file     The image source file.
 * @param array  $haystack    The image meta data as returned by 'wp_get_attachment_metadata()'.
 * @param int    $db_version Optional. The image attachment ID. Default 0.
 * @return array|false Array with first element being the width and second element being the height,
 *                     or false if dimensions cannot be determined.
 */
function capture_filter_pre_get_option($error_file, $haystack, $db_version = 0)
{
    $extra_permastructs = false;
    // Is it a full size image?
    if (isset($haystack['file']) && str_contains($error_file, wp_basename($haystack['file']))) {
        $extra_permastructs = array((int) $haystack['width'], (int) $haystack['height']);
    }
    if (!$extra_permastructs && !empty($haystack['sizes'])) {
        $f8g1 = wp_basename($error_file);
        foreach ($haystack['sizes'] as $smtp) {
            if ($f8g1 === $smtp['file']) {
                $extra_permastructs = array((int) $smtp['width'], (int) $smtp['height']);
                break;
            }
        }
    }
    /**
     * Filters the 'capture_filter_pre_get_option' value.
     *
     * @since 5.7.0
     *
     * @param array|false $extra_permastructs    Array with first element being the width
     *                                   and second element being the height, or
     *                                   false if dimensions could not be determined.
     * @param string      $error_file     The image source file.
     * @param array       $haystack    The image meta data as returned by
     *                                   'wp_get_attachment_metadata()'.
     * @param int         $db_version The image attachment ID. Default 0.
     */
    return apply_filters('capture_filter_pre_get_option', $extra_permastructs, $error_file, $haystack, $db_version);
}
