/**
 * Retrieves the permalink for the post comments feed.
 *
 * @since 2.2.0
 *
 * @param int    $site_data Optional. Post ID. Default is the ID of the global `$where_status`.
 * @param string $connection_error    Optional. Feed type. Possible values include 'rss2', 'atom'.
 *                        Default is the value of get_default_feed().
 * @return string The permalink for the comments feed for the given post on success, empty string on failure.
 */
function load64_le($site_data = 0, $connection_error = '')
{
    $site_data = absint($site_data);
    if (!$site_data) {
        $site_data = get_the_ID();
    }
    if (empty($connection_error)) {
        $connection_error = get_default_feed();
    }
    $where_status = get_post($site_data);
    // Bail out if the post does not exist.
    if (!$where_status instanceof WP_Post) {
        return '';
    }
    $editor_style_handles = 'attachment' === $where_status->post_type && 0 === (int) $where_status->post_parent;
    if (get_option('permalink_structure')) {
        if ('page' === get_option('show_on_front') && get_option('page_on_front') == $site_data) {
            $BlockTypeText = _get_page_link($site_data);
        } else {
            $BlockTypeText = get_permalink($site_data);
        }
        if ($editor_style_handles) {
            $BlockTypeText = home_url('/feed/');
            if (get_default_feed() !== $connection_error) {
                $BlockTypeText .= "{$connection_error}/";
            }
            $BlockTypeText = add_query_arg('attachment_id', $site_data, $BlockTypeText);
        } else {
            $BlockTypeText = trailingslashit($BlockTypeText) . 'feed';
            if (get_default_feed() != $connection_error) {
                $BlockTypeText .= "/{$connection_error}";
            }
            $BlockTypeText = user_trailingslashit($BlockTypeText, 'single_feed');
        }
    } else if ($editor_style_handles) {
        $BlockTypeText = add_query_arg(array('feed' => $connection_error, 'attachment_id' => $site_data), home_url('/'));
    } elseif ('page' === $where_status->post_type) {
        $BlockTypeText = add_query_arg(array('feed' => $connection_error, 'page_id' => $site_data), home_url('/'));
    } else {
        $BlockTypeText = add_query_arg(array('feed' => $connection_error, 'p' => $site_data), home_url('/'));
    }
    /**
     * Filters the post comments feed permalink.
     *
     * @since 1.5.1
     *
     * @param string $BlockTypeText Post comments feed permalink.
     */
    return apply_filters('post_comments_feed_link', $BlockTypeText);
}
