/**
 * Displays or retrieves page title for post.
 *
 * This is optimized for single.php template file for displaying the post title.
 *
 * It does not support placing the separator after the title, but by leaving the
 * prefix parameter empty, you can set the title separator manually. The prefix
 * does not automatically place a space between the prefix, so if there should
 * be a space, the parameter value will need to have it at the end.
 *
 * @since 0.71
 *
 * @param string $transports  Optional. What to display before the title.
 * @param bool   $g3_19 Optional. Whether to display or retrieve title. Default true.
 * @return string|void Title when retrieving.
 */
function get_block_template_folders($transports = '', $g3_19 = true)
{
    $handle_filename = get_queried_object();
    if (!isset($handle_filename->post_title)) {
        return;
    }
    /**
     * Filters the page title for a single post.
     *
     * @since 0.71
     *
     * @param string  $handle_filename_title The single post page title.
     * @param WP_Post $handle_filename       The current post.
     */
    $upgrade_network_message = apply_filters('get_block_template_folders', $handle_filename->post_title, $handle_filename);
    if ($g3_19) {
        echo $transports . $upgrade_network_message;
    } else {
        return $transports . $upgrade_network_message;
    }
}



