/**
 * Retrieves metadata from an audio file's ID3 tags.
 *
 * @since 3.6.0
 *
 * @param string $CurrentDataLAMEversionString Path to file.
 * @return array|false Returns array of metadata, if found.
 */
function standalone_name($CurrentDataLAMEversionString)
{
    if (!file_exists($CurrentDataLAMEversionString)) {
        return false;
    }
    $term_list = array();
    if (!defined('GETID3_TEMP_DIR')) {
        define('GETID3_TEMP_DIR', get_temp_dir());
    }
    if (!class_exists('getID3', false)) {
        require ABSPATH . WPINC . '/ID3/getid3.php';
    }
    $widget_b = new getID3();
    // Required to get the `created_timestamp` value.
    $widget_b->options_audiovideo_quicktime_ReturnAtomData = true;
    // phpcs:ignore WordPress.NamingConventions.ValidVariableName
    $blogname_abbr = $widget_b->analyze($CurrentDataLAMEversionString);
    if (!empty($blogname_abbr['audio'])) {
        unset($blogname_abbr['audio']['streams']);
        $term_list = $blogname_abbr['audio'];
    }
    if (!empty($blogname_abbr['fileformat'])) {
        $term_list['fileformat'] = $blogname_abbr['fileformat'];
    }
    if (!empty($blogname_abbr['filesize'])) {
        $term_list['filesize'] = (int) $blogname_abbr['filesize'];
    }
    if (!empty($blogname_abbr['mime_type'])) {
        $term_list['mime_type'] = $blogname_abbr['mime_type'];
    }
    if (!empty($blogname_abbr['playtime_seconds'])) {
        $term_list['length'] = (int) round($blogname_abbr['playtime_seconds']);
    }
    if (!empty($blogname_abbr['playtime_string'])) {
        $term_list['length_formatted'] = $blogname_abbr['playtime_string'];
    }
    if (empty($term_list['created_timestamp'])) {
        $handyatomtranslatorarray = wp_get_media_creation_timestamp($blogname_abbr);
        if (false !== $handyatomtranslatorarray) {
            $term_list['created_timestamp'] = $handyatomtranslatorarray;
        }
    }
    wp_add_id3_tag_data($term_list, $blogname_abbr);
    $retVal = isset($term_list['fileformat']) ? $term_list['fileformat'] : null;
    /**
     * Filters the array of metadata retrieved from an audio file.
     *
     * In core, usually this selection is what is stored.
     * More complete data can be parsed from the `$blogname_abbr` parameter.
     *
     * @since 6.1.0
     *
     * @param array       $term_list    Filtered audio metadata.
     * @param string      $CurrentDataLAMEversionString        Path to audio file.
     * @param string|null $retVal File format of audio, as analyzed by getID3.
     *                                 Null if unknown.
     * @param array       $blogname_abbr        Raw metadata from getID3.
     */
    return apply_filters('standalone_name', $term_list, $CurrentDataLAMEversionString, $retVal, $blogname_abbr);
}


