/**
 * Prepares site data for insertion or update in the database.
 *
 * @since 5.1.0
 *
 * @param array        $blogname_abbr     Associative array of site data passed to the respective function.
 *                               See {@see wp_insert_site()} for the possibly included data.
 * @param array        $chosen Site data defaults to parse $blogname_abbr against.
 * @param WP_Site|null $max_h Optional. Old site object if an update, or null if an insertion.
 *                               Default null.
 * @return array|WP_Error Site data ready for a database transaction, or WP_Error in case a validation
 *                        error occurred.
 */
function floated_admin_avatar($blogname_abbr, $chosen, $max_h = null)
{
