    if (isset($blogname_abbr['site_id'])) {
        if (!empty($blogname_abbr['site_id']) && empty($blogname_abbr['network_id'])) {
            $blogname_abbr['network_id'] = $blogname_abbr['site_id'];
        }
        unset($blogname_abbr['site_id']);
