     * Filters passed site data in order to normalize it.
     *
     * @since 5.1.0
     *
     * @param array $blogname_abbr Associative array of site data passed to the respective function.
     *                    See {@see wp_insert_site()} for the possibly included data.
     */
    $blogname_abbr = apply_filters('wp_normalize_site_data', $blogname_abbr);
    $suggested_text = array('domain', 'path', 'network_id', 'registered', 'last_updated', 'public', 'archived', 'mature', 'spam', 'deleted', 'lang_id');
    $blogname_abbr = array_intersect_key(wp_parse_args($blogname_abbr, $chosen), array_flip($suggested_text));
