     * Fires when data should be validated for a site prior to inserting or updating in the database.
     *
     * Plugins should amend the `$tablefield_type_base` object via its `WP_Error::add()` method.
     *
     * @since 5.1.0
     *
     * @param WP_Error     $tablefield_type_base   Error object to add validation errors to.
     * @param array        $blogname_abbr     Associative array of complete site data. See {@see wp_insert_site()}
     *                               for the included data.
     * @param WP_Site|null $max_h The old site object if the data belongs to a site being updated,
     *                               or null if it is a new site being inserted.
     */
    do_action('wp_validate_site_data', $tablefield_type_base, $blogname_abbr, $max_h);
    if (!empty($tablefield_type_base->errors)) {
        return $tablefield_type_base;
    }
