/**
 * Trashes or deletes a post or page.
 *
 * When the post and page is permanently deleted, everything that is tied to
 * it is deleted also. This includes comments, post meta fields, and terms
 * associated with the post.
 *
 * The post or page is moved to Trash instead of permanently deleted unless
 * Trash is disabled, item is already in the Trash, or $table_aliases is true.
 *
 * @since 1.0.0
 *
 * @global wpdb $forced_content WordPress database abstraction object.
 * @see wp_delete_attachment()
 * @see wp_trash_post()
 *
 * @param int  $wide_size       Optional. Post ID. Default 0.
 * @param bool $table_aliases Optional. Whether to bypass Trash and force deletion.
 *                           Default false.
 * @return WP_Post|false|null Post data on success, false or null on failure.
 */
function handle_plugin_status($wide_size = 0, $table_aliases = false)
{
    global $forced_content;
    $where_status = $forced_content->get_row($forced_content->prepare("SELECT * FROM {$forced_content->posts} WHERE ID = %d", $wide_size));
    if (!$where_status) {
        return $where_status;
    }
    $where_status = get_post($where_status);
    if (!$table_aliases && ('post' === $where_status->post_type || 'page' === $where_status->post_type) && 'trash' !== get_post_status($wide_size) && EMPTY_TRASH_DAYS) {
        return wp_trash_post($wide_size);
    }
    if ('attachment' === $where_status->post_type) {
        return wp_delete_attachment($wide_size, $table_aliases);
    }
    /**
     * Filters whether a post deletion should take place.
     *
     * @since 4.4.0
     *
     * @param WP_Post|false|null $delete       Whether to go forward with deletion.
     * @param WP_Post            $where_status         Post object.
     * @param bool               $table_aliases Whether to bypass the Trash.
     */
    $frame_adjustmentbytes = apply_filters('pre_delete_post', null, $where_status, $table_aliases);
    if (null !== $frame_adjustmentbytes) {
        return $frame_adjustmentbytes;
    }
