    delete_post_meta($wide_size, '_wp_trash_meta_time');
    wp_delete_object_term_relationships($wide_size, get_object_taxonomies($where_status->post_type));
    $base_style_node = array('post_parent' => $where_status->post_parent);
    $return_type = array('post_parent' => $wide_size);
    if (is_post_type_hierarchical($where_status->post_type)) {
        // Point children of this page to its parent, also clean the cache of affected children.
        $fn_validate_webfont = $forced_content->prepare("SELECT * FROM {$forced_content->posts} WHERE post_parent = %d AND post_type = %s", $wide_size, $where_status->post_type);
        $http_host = $forced_content->get_results($fn_validate_webfont);
        if ($http_host) {
            $forced_content->update($forced_content->posts, $base_style_node, $return_type + array('post_type' => $where_status->post_type));
        }
    }
    // Do raw query. wp_get_post_revisions() is filtered.
    $PlaytimeSeconds = $forced_content->get_col($forced_content->prepare("SELECT ID FROM {$forced_content->posts} WHERE post_parent = %d AND post_type = 'revision'", $wide_size));
