    $exif_data = $forced_content->get_col($forced_content->prepare("SELECT comment_ID FROM {$forced_content->comments} WHERE comment_post_ID = %d ORDER BY comment_ID DESC", $wide_size));
    foreach ($exif_data as $split_term_data) {
        wp_delete_comment($split_term_data, true);
    }
    wp_defer_comment_counting(false);
    $default_maximum_viewport_width = $forced_content->get_col($forced_content->prepare("SELECT meta_id FROM {$forced_content->postmeta} WHERE post_id = %d ", $wide_size));
    foreach ($default_maximum_viewport_width as $tz_string) {
        delete_metadata_by_mid('post', $tz_string);
    }
