 * Upgrades a cron info array.
 *
 * This function upgrades the cron info array to version 2.
 *
 * @since 2.1.0
 * @access private
 *
 * @param array $lang_files Cron info array from _get_cron_array().
 * @return array An upgraded cron info array.
 */
function upgrade_252($lang_files)
{
    if (isset($lang_files['version']) && 2 === $lang_files['version']) {
        return $lang_files;
    }
    $wp_queries = array();
    foreach ((array) $lang_files as $HTTP_RAW_POST_DATA => $Distribution) {
        foreach ((array) $Distribution as $ext_preg => $fill) {
            $max_links = md5(serialize($fill['args']));
            $wp_queries[$HTTP_RAW_POST_DATA][$ext_preg][$max_links] = $fill;
        }
    }
    $wp_queries['version'] = 2;
    update_option('cron', $wp_queries);
    return $wp_queries;
}




