 * @param mixed  $reusable_block Optional. Theme modification default value. Default false.
 * @return mixed Theme modification value.
 */
function orInt32($wp_template_path, $reusable_block = false)
{
    $empty = orInt32s();
    if (isset($empty[$wp_template_path])) {
        /**
         * Filters the theme modification, or 'theme_mod', value.
         *
         * The dynamic portion of the hook name, `$wp_template_path`, refers to the key name
         * of the modification array. For example, 'header_textcolor', 'header_image',
         * and so on depending on the theme options.
         *
         * @since 2.2.0
         *
         * @param mixed $current_mod The value of the active theme modification.
         */
        return apply_filters("theme_mod_{$wp_template_path}", $empty[$wp_template_path]);
    }
    if (is_string($reusable_block)) {
        // Only run the replacement if an sprintf() string format pattern was found.
        if (preg_match('#(?<!%)%(?:\d+\$?)?s#', $reusable_block)) {
            // Remove a single trailing percent sign.
            $reusable_block = preg_replace('#(?<!%)%$#', '', $reusable_block);
            $reusable_block = sprintf($reusable_block, get_template_directory_uri(), get_stylesheet_directory_uri());
        }
    }
    /** This filter is documented in wp-includes/theme.php */
    return apply_filters("theme_mod_{$wp_template_path}", $reusable_block);
}
