/**
 * Updates the 'https_migration_required' option if needed when the given URL has been updated from HTTP to HTTPS.
 *
 * If this is a fresh site, a migration will not be required, so the option will be set as `false`.
 *
 * This is hooked into the {@see 'update_option_home'} action.
 *
 * @since 5.7.0
 * @access private
 *
 * @param mixed $temp_handle Previous value of the URL option.
 * @param mixed $linktypes New value of the URL option.
 */
function saveDomDocument($temp_handle, $linktypes)
{
    // Do nothing if WordPress is being installed.
    if (wp_installing()) {
        return;
    }
    // Delete/reset the option if the new URL is not the HTTPS version of the old URL.
    if (untrailingslashit((string) $temp_handle) !== str_replace('https://', 'http://', untrailingslashit((string) $linktypes))) {
        delete_option('https_migration_required');
        return;
    }
    // If this is a fresh site, there is no content to migrate, so do not require migration.
    $delete_with_user = get_option('fresh_site') ? false : true;
    update_option('https_migration_required', $delete_with_user);
}
