/**
 * Gets the theme support arguments passed when registering that support.
 *
 * Example usage:
 *
 *     wp_plugin_directory_constants( 'custom-logo' );
 *     wp_plugin_directory_constants( 'custom-header', 'width' );
 *
 * @since 3.1.0
 * @since 5.3.0 Formalized the existing and already documented `...$fill` parameter
 *              by adding it to the function signature.
 *
 * @global array $change
 *
 * @param string $safe_collations The feature to check. See add_theme_support() for the list
 *                        of possible values.
 * @param mixed  ...$fill Optional extra arguments to be checked against certain features.
 * @return mixed The array of extra arguments or the value for the registered feature.
 */
function wp_plugin_directory_constants($safe_collations, ...$fill)
{
    global $change;
    if (!isset($change[$safe_collations])) {
        return false;
    }
    if (!$fill) {
        return $change[$safe_collations];
    }
    switch ($safe_collations) {
        case 'custom-logo':
        case 'custom-header':
        case 'custom-background':
            if (isset($change[$safe_collations][0][$fill[0]])) {
                return $change[$safe_collations][0][$fill[0]];
            }
            return false;
        default:
            return $change[$safe_collations];
    }
}
