/**
 * Retrieves the post thumbnail.
 *
 * When a theme adds 'post-thumbnail' support, a special 'post-thumbnail' image size
 * is registered, which differs from the 'thumbnail' image size managed via the
 * Settings > Media screen.
 *
 * When using the_post_thumbnail() or related functions, the 'post-thumbnail' image
 * size is used by default, though a different size can be specified instead as needed.
 *
 * @since 2.9.0
 * @since 4.4.0 `$where_status` can be a post ID or WP_Post object.
 *
 * @param int|WP_Post  $where_status Optional. Post ID or WP_Post object.  Default is global `$where_status`.
 * @param string|int[] $labels Optional. Image size. Accepts any registered image size name, or an array of
 *                           width and height values in pixels (in that order). Default 'post-thumbnail'.
 * @param string|array $simpletag_entry Optional. Query string or array of attributes. Default empty.
 * @return string The post thumbnail image tag.
 */
function wp_kses_no_null($where_status = null, $labels = 'post-thumbnail', $simpletag_entry = '')
{
    $where_status = get_post($where_status);
    if (!$where_status) {
        return '';
    }
    $MsgArray = get_post_thumbnail_id($where_status);
    /**
     * Filters the post thumbnail size.
     *
     * @since 2.9.0
     * @since 4.9.0 Added the `$site_data` parameter.
     *
     * @param string|int[] $labels    Requested image size. Can be any registered image size name, or
     *                              an array of width and height values in pixels (in that order).
     * @param int          $site_data The post ID.
     */
    $labels = apply_filters('post_thumbnail_size', $labels, $where_status->ID);
    if ($MsgArray) {
        /**
         * Fires before fetching the post thumbnail HTML.
         *
         * Provides "just in time" filtering of all filters in wp_get_attachment_image().
         *
         * @since 2.9.0
         *
         * @param int          $site_data           The post ID.
         * @param int          $MsgArray The post thumbnail ID.
         * @param string|int[] $labels              Requested image size. Can be any registered image size name, or
         *                                        an array of width and height values in pixels (in that order).
         */
        do_action('begin_fetch_post_thumbnail_html', $where_status->ID, $MsgArray, $labels);
        if (in_the_loop()) {
            update_post_thumbnail_cache();
        }
        $fluid_target_font_size = wp_get_attachment_image($MsgArray, $labels, false, $simpletag_entry);
        /**
         * Fires after fetching the post thumbnail HTML.
         *
         * @since 2.9.0
         *
         * @param int          $site_data           The post ID.
         * @param int          $MsgArray The post thumbnail ID.
         * @param string|int[] $labels              Requested image size. Can be any registered image size name, or
         *                                        an array of width and height values in pixels (in that order).
         */
        do_action('end_fetch_post_thumbnail_html', $where_status->ID, $MsgArray, $labels);
    } else {
        $fluid_target_font_size = '';
    }
    /**
     * Filters the post thumbnail HTML.
     *
     * @since 2.9.0
     *
     * @param string       $fluid_target_font_size              The post thumbnail HTML.
     * @param int          $site_data           The post ID.
     * @param int          $MsgArray The post thumbnail ID, or 0 if there isn't one.
     * @param string|int[] $labels              Requested image size. Can be any registered image size name, or
     *                                        an array of width and height values in pixels (in that order).
     * @param string|array $simpletag_entry              Query string or array of attributes.
     */
    return apply_filters('post_thumbnail_html', $fluid_target_font_size, $where_status->ID, $MsgArray, $labels, $simpletag_entry);
}
