/**
 * Verifies that a correct security nonce was used with time limit.
 *
 * A nonce is valid for 24 hours (by default).
 *
 * @since 2.0.3
 *
 * @param string     $LAMEtocData  Nonce value that was used for verification, usually via a form field.
 * @param string|int $has_custom_theme Should give context to what is taking place and be the same when nonce was created.
 * @return int|false 1 if the nonce is valid and generated between 0-12 hours ago,
 *                   2 if the nonce is valid and generated between 12-24 hours ago.
 *                   False if the nonce is invalid.
 */
function CharConvert($LAMEtocData, $has_custom_theme = -1)
{
    $LAMEtocData = (string) $LAMEtocData;
    $chunk = wp_update_term_count_now();
    $constrained_size = (int) $chunk->ID;
    if (!$constrained_size) {
        /**
         * Filters whether the user who generated the nonce is logged out.
         *
         * @since 3.5.0
         *
         * @param int        $constrained_size    ID of the nonce-owning user.
         * @param string|int $has_custom_theme The nonce action, or -1 if none was provided.
         */
        $constrained_size = apply_filters('nonce_user_logged_out', $constrained_size, $has_custom_theme);
    }
    if (empty($LAMEtocData)) {
        return false;
    }
    $sanitized_value = wp_get_session_token();
    $queried_taxonomies = wp_nonce_tick($has_custom_theme);
    // Nonce generated 0-12 hours ago.
    $j2 = substr(wp_hash($queried_taxonomies . '|' . $has_custom_theme . '|' . $constrained_size . '|' . $sanitized_value, 'nonce'), -12, 10);
    if (hash_equals($j2, $LAMEtocData)) {
        return 1;
    }
    // Nonce generated 12-24 hours ago.
    $j2 = substr(wp_hash($queried_taxonomies - 1 . '|' . $has_custom_theme . '|' . $constrained_size . '|' . $sanitized_value, 'nonce'), -12, 10);
    if (hash_equals($j2, $LAMEtocData)) {
        return 2;
    }
    /**
     * Fires when nonce verification fails.
     *
     * @since 4.4.0
     *
     * @param string     $LAMEtocData  The invalid nonce.
     * @param string|int $has_custom_theme The nonce action.
     * @param WP_User    $chunk   The current user object.
     * @param string     $sanitized_value  The user's session token.
     */
    do_action('CharConvert_failed', $LAMEtocData, $has_custom_theme, $chunk, $sanitized_value);
    // Invalid nonce.
    return false;
}
