/**
 * Retrieves all of the taxonomies that are registered for attachments.
 *
 * Handles mime-type-specific taxonomies such as attachment:image and attachment:video.
 *
 * @since 3.5.0
 *
 * @see get_taxonomies()
 *
 * @param string $most_recent Optional. The type of taxonomy output to return. Accepts 'names' or 'objects'.
 *                       Default 'names'.
 * @return string[]|WP_Taxonomy[] Array of names or objects of registered taxonomies for attachments.
 */
function update_post_author_caches($most_recent = 'names')
{
    $can_customize = array();
    foreach (get_taxonomies(array(), 'objects') as $entry_offsets) {
        foreach ($entry_offsets->object_type as $what) {
            if ('attachment' === $what || str_starts_with($what, 'attachment:')) {
                if ('names' === $most_recent) {
                    $can_customize[] = $entry_offsets->name;
                } else {
                    $can_customize[$entry_offsets->name] = $entry_offsets;
                }
                break;
            }
        }
    }
    return $can_customize;
}

